def get_device():
    try:
        import torch_npu
    except ImportError as exc:
        raise RuntimeError(
            "Ascend NPU validation requires torch_npu; CPU/CUDA fallback is not allowed."
        ) from exc

    npu_backend = getattr(torch_npu, "npu")
    if not npu_backend.is_available():
        raise RuntimeError(
            "Ascend NPU validation requires an available NPU; CPU/CUDA fallback is not allowed."
        )

    print("✓ 检测到 Ascend NPU 可用")
    return "npu"
